const { PrismaClient } = require('@prisma/client');
const p = new PrismaClient();

const codingQuestions = [
  // Lesson 45 - Express Routing coding
  {lessonId:45,difficulty:"Easy",title:"Modular Router Setup",problemStatement:"Create an Express app with modular routers: /api/v1/users, /api/v1/products. Each router is in its own file with at least GET / and GET /:id routes.",examples:"GET /api/v1/users -> list. GET /api/v1/users/1 -> single user.",starterCodeJs:"// routes/v1/users.js\nconst router = require('express').Router();\nconst users = [{id:1,name:'Alice'},{id:2,name:'Bob'}];\nrouter.get('/', (req,res) => res.json({data:users,count:users.length}));\nrouter.get('/:id', (req,res) => {\n  const user = users.find(u => u.id === parseInt(req.params.id));\n  user ? res.json(user) : res.status(404).json({error:'Not found'});\n});\nmodule.exports = router;\n// app.js\nconst express = require('express');\nconst app = express();\napp.use(express.json());\nconst v1 = express.Router();\nv1.use('/users', require('./routes/v1/users'));\nv1.use('/products', require('./routes/v1/products'));\napp.use('/api/v1', v1);",hints:"Nest routers: api/v1 router mounts users/products routers. This makes versioning easy - add /api/v2 router later.",solutionExplanation:"Hierarchical router composition: app -> v1 router -> resource routers. Each level is independently testable."},
  {lessonId:45,difficulty:"Medium",title:"Route Parameter Preprocessing",problemStatement:"Use router.param() to load a user from DB once for all routes using :userId. The loaded user is attached to req.user.",examples:"router.param('userId', ...) runs before GET /users/:userId/posts and all other :userId routes.",starterCodeJs:"const router = require('express').Router();\nconst db = require('../db');\nrouter.param('userId', async (req, res, next, id) => {\n  try {\n    const user = await db.user.findUnique({ where: { id: parseInt(id) } });\n    if (!user) return res.status(404).json({ error: 'User not found' });\n    req.loadedUser = user;\n    next();\n  } catch (err) { next(err); }\n});\nrouter.param('postId', async (req, res, next, id) => {\n  try {\n    const post = await db.post.findUnique({ where: { id: parseInt(id) } });\n    if (!post) return res.status(404).json({ error: 'Post not found' });\n    req.loadedPost = post;\n    next();\n  } catch (err) { next(err); }\n});\nrouter.get('/users/:userId', (req, res) => res.json(req.loadedUser));\nrouter.get('/users/:userId/posts', async (req, res) => {\n  const posts = await db.post.findMany({ where: { authorId: req.loadedUser.id } });\n  res.json(posts);\n});",hints:"router.param fires once per unique param per request. Attach loaded entity to req object. Centralizes 404 handling.",solutionExplanation:"router.param avoids duplicating lookup+404 logic in every route. Preloaded entities available on req for all matching routes."},
  {lessonId:45,difficulty:"Medium",title:"Nested Resource Routes",problemStatement:"Build nested routes for /posts/:postId/comments (CRUD). A comment belongs to a post. Validate post exists before any comment operation.",examples:"GET /posts/1/comments, POST /posts/1/comments, DELETE /posts/1/comments/5",starterCodeJs:"const router = require('express').Router({ mergeParams: true });\nconst db = require('../db');\nasync function ensurePost(req, res, next) {\n  const post = await db.post.findUnique({ where: { id: parseInt(req.params.postId) } });\n  if (!post) return res.status(404).json({ error: 'Post not found' });\n  req.post = post;\n  next();\n}\nrouter.use(ensurePost);\nrouter.get('/', async (req, res) => {\n  const comments = await db.comment.findMany({ where: { postId: req.post.id }, orderBy: { createdAt: 'asc' } });\n  res.json(comments);\n});\nrouter.post('/', async (req, res) => {\n  const { body } = req.body;\n  if (!body) return res.status(400).json({ error: 'body required' });\n  const comment = await db.comment.create({ data: { body, postId: req.post.id, authorId: req.user.id } });\n  res.status(201).json(comment);\n});\nrouter.delete('/:commentId', async (req, res) => {\n  await db.comment.delete({ where: { id: parseInt(req.params.commentId), postId: req.post.id } });\n  res.status(204).end();\n});\n// In parent router: app.use('/posts/:postId/comments', commentRouter)",hints:"mergeParams:true makes parent :postId available in nested router. Middleware ensures post exists before all routes.",solutionExplanation:"mergeParams:true required to access parent route params. Scoped DELETE ensures comment belongs to the post (prevents deleting other posts' comments)."},
  {lessonId:45,difficulty:"Hard",title:"Route-level Caching",problemStatement:"Build a route decorator that caches route responses in Redis (simulated with Map). Cache key includes route path and query string. Invalidate on mutations.",examples:"cachedRoute(60)(handler) caches for 60s. POST/PUT/DELETE to same resource invalidates cache.",starterCodeJs:"const cache = new Map();\nfunction cached(ttlSeconds, keyFn) {\n  return (req, res, next) => {\n    const key = keyFn ? keyFn(req) : `${req.method}:${req.originalUrl}`;\n    const hit = cache.get(key);\n    if (hit && Date.now() < hit.exp) {\n      return res.set('X-Cache','HIT').set('Content-Type','application/json').send(hit.data);\n    }\n    const origJson = res.json.bind(res);\n    res.json = data => {\n      if (res.statusCode < 300) cache.set(key, { data: JSON.stringify(data), exp: Date.now() + ttlSeconds*1000 });\n      res.set('X-Cache','MISS');\n      return origJson(data);\n    };\n    next();\n  };\n}\nfunction invalidatePattern(pattern) {\n  return (req, res, next) => {\n    const regex = new RegExp(pattern);\n    for (const k of cache.keys()) if (regex.test(k)) cache.delete(k);\n    next();\n  };\n}\n// Usage:\nrouter.get('/products', cached(300), listProducts);\nrouter.post('/products', invalidatePattern('GET:/products'), createProduct);",hints:"Intercept res.json to capture response before caching. Pattern-based invalidation clears related cache keys. Custom keyFn for flexible cache keys.",solutionExplanation:"Intercept+cache pattern: wrap res.json to save response. invalidatePattern uses regex to bulk-delete related cache entries on mutation."},
  {lessonId:45,difficulty:"Easy",title:"API Versioning",problemStatement:"Implement API versioning in Express. Support v1 and v2 of /api/users where v2 adds pagination and a different response format.",examples:"GET /api/v1/users -> [{id,name}]. GET /api/v2/users?page=1&limit=10 -> {data:[...],meta:{page,total}}",starterCodeJs:"const express = require('express');\nconst app = express();\nconst users = Array.from({length:25}, (_,i) => ({id:i+1,name:`User ${i+1}`,email:`user${i+1}@test.com`}));\n// V1 - simple array response\nconst v1 = express.Router();\nv1.get('/users', (req, res) => res.json(users.map(u => ({id:u.id,name:u.name}))));\napp.use('/api/v1', v1);\n// V2 - paginated with meta\nconst v2 = express.Router();\nv2.get('/users', (req, res) => {\n  const page = parseInt(req.query.page) || 1;\n  const limit = Math.min(parseInt(req.query.limit) || 10, 50);\n  const total = users.length;\n  const data = users.slice((page-1)*limit, page*limit);\n  res.json({ data, meta: { page, limit, total, pages: Math.ceil(total/limit) } });\n});\napp.use('/api/v2', v2);",hints:"Separate router instances per version. V2 adds pagination without breaking V1 consumers.",solutionExplanation:"URL versioning: /api/v1 and /api/v2 routers. V2 enhances V1 response with meta. Old clients continue using V1."},
  {lessonId:45,difficulty:"Medium",title:"Route Guard Pattern",problemStatement:"Build route guards: requireAuth (JWT check), requireRole('admin'), and requireOwnership (user can only modify their own resources).",examples:"router.delete('/posts/:id', requireAuth, requireOwnership('post'), deletePost)",starterCodeJs:"const jwt = require('jsonwebtoken');\nfunction requireAuth(req, res, next) {\n  const token = req.headers.authorization?.replace('Bearer ', '');\n  if (!token) return res.status(401).json({ error: 'Authentication required' });\n  try { req.user = jwt.verify(token, process.env.JWT_SECRET); next(); }\n  catch { res.status(401).json({ error: 'Invalid or expired token' }); }\n}\nfunction requireRole(...roles) {\n  return (req, res, next) => {\n    if (!req.user) return res.status(401).json({ error: 'Not authenticated' });\n    if (!roles.includes(req.user.role)) return res.status(403).json({ error: 'Insufficient permissions' });\n    next();\n  };\n}\nfunction requireOwnership(resource) {\n  return async (req, res, next) => {\n    const db = require('../db');\n    const id = parseInt(req.params.id || req.params[`${resource}Id`]);\n    const record = await db[resource].findUnique({ where: { id } });\n    if (!record) return res.status(404).json({ error: 'Not found' });\n    if (record.authorId !== req.user.sub && req.user.role !== 'admin') return res.status(403).json({ error: 'Forbidden' });\n    req[resource] = record;\n    next();\n  };\n}",hints:"requireAuth sets req.user. requireRole checks req.user.role. requireOwnership loads resource and compares authorId. Admin bypasses ownership.",solutionExplanation:"Guards compose via middleware chain. Each guard calls next() on success or sends error response. Admin bypass prevents admin lockout."},
  {lessonId:45,difficulty:"Hard",title:"Request Context with AsyncLocalStorage",problemStatement:"Use Node.js AsyncLocalStorage to pass request context (user, requestId) through the entire call stack without prop drilling.",examples:"Any function called during a request can call getRequestContext() to get req.user and requestId.",starterCodeJs:"const { AsyncLocalStorage } = require('async_hooks');\nconst storage = new AsyncLocalStorage();\nfunction requestContext(req, res, next) {\n  const context = {\n    requestId: req.headers['x-request-id'] || Math.random().toString(36).slice(2),\n    user: req.user || null,\n    startTime: Date.now()\n  };\n  res.setHeader('X-Request-ID', context.requestId);\n  storage.run(context, next);\n}\nfunction getRequestContext() {\n  return storage.getStore();\n}\nfunction logWithContext(message, data = {}) {\n  const ctx = getRequestContext();\n  console.log(JSON.stringify({ ...data, message, requestId: ctx?.requestId, userId: ctx?.user?.id, time: new Date().toISOString() }));\n}\n// Use in service functions without passing req:\nasync function sendEmail(to, subject) {\n  const ctx = getRequestContext();\n  logWithContext('Sending email', { to, subject, triggeredBy: ctx?.user?.email });\n}",hints:"AsyncLocalStorage.run() creates a context that persists through all async calls within that scope. getStore() retrieves it anywhere in the call chain.",solutionExplanation:"AsyncLocalStorage is the Node.js answer to thread-local storage. storage.run(ctx, fn) makes ctx available in fn and all its async descendants."},
  {lessonId:45,difficulty:"Easy",title:"RESTful Resource Helper",problemStatement:"Build a function restResource(router, name, handlers) that auto-wires standard REST routes for a resource (index, show, create, update, destroy).",examples:"restResource(router, 'post', {index, show, create, update, destroy}) creates 5 routes.",starterCodeJs:"function restResource(router, name, handlers) {\n  const plural = `/${name}s`;\n  const singular = `/${name}s/:id`;\n  if (handlers.index) router.get(plural, handlers.index);\n  if (handlers.create) router.post(plural, handlers.create);\n  if (handlers.show) router.get(singular, handlers.show);\n  if (handlers.update) {\n    router.put(singular, handlers.update);\n    router.patch(singular, handlers.update);\n  }\n  if (handlers.destroy) router.delete(singular, handlers.destroy);\n  return router;\n}\n// Usage:\nrestResource(router, 'user', {\n  index: async (req, res) => res.json(await db.user.findMany()),\n  show: async (req, res) => {\n    const user = await db.user.findUnique({ where: { id: parseInt(req.params.id) } });\n    user ? res.json(user) : res.status(404).json({ error: 'Not found' });\n  },\n  create: async (req, res) => res.status(201).json(await db.user.create({ data: req.body })),\n  destroy: async (req, res) => { await db.user.delete({ where: { id: parseInt(req.params.id) } }); res.status(204).end(); }\n});",hints:"Check handler existence before wiring. Both PUT and PATCH map to update. Plural path for collection, singular with :id for individual.",solutionExplanation:"Convention over configuration: standard REST routes are always the same. This function eliminates boilerplate. Rails-inspired resourceful routing."},
  {lessonId:45,difficulty:"Medium",title:"Route Testing with Supertest",problemStatement:"Write integration tests for an Express router using supertest. Test GET list, GET single (found and 404), POST (valid and invalid), and DELETE.",examples:"const res = await request(app).get('/api/users/1').expect(200). Verify response body.",starterCodeJs:"const request = require('supertest');\nconst app = require('../app');\ndescribe('Users API', () => {\n  describe('GET /api/users', () => {\n    it('returns user list', async () => {\n      const res = await request(app).get('/api/users').expect(200);\n      expect(Array.isArray(res.body)).toBe(true);\n    });\n  });\n  describe('GET /api/users/:id', () => {\n    it('returns 200 for existing user', async () => {\n      const res = await request(app).get('/api/users/1').expect(200);\n      expect(res.body).toHaveProperty('id', 1);\n    });\n    it('returns 404 for missing user', async () => {\n      await request(app).get('/api/users/99999').expect(404);\n    });\n  });\n  describe('POST /api/users', () => {\n    it('creates user with valid data', async () => {\n      const res = await request(app).post('/api/users').send({name:'Test',email:'test@test.com'}).expect(201);\n      expect(res.body).toHaveProperty('id');\n    });\n    it('returns 400 for missing email', async () => {\n      await request(app).post('/api/users').send({name:'Test'}).expect(400);\n    });\n  });\n});",hints:"supertest wraps the Express app - no need to start a real server. .expect(status) asserts status code. .send() sets JSON body.",solutionExplanation:"Integration tests with supertest: test the full request/response cycle including middleware. No mocking needed for simple in-memory or test DB setups."},
  {lessonId:45,difficulty:"Hard",title:"Dynamic Route Generator",problemStatement:"Build a function that generates Express routes from a config object. Config specifies path, method, middleware array, validation schema, and handler.",examples:"generateRoute({method:'post', path:'/users', middleware:[auth], validate:schema, handler:createUser})",starterCodeJs:"function generateRoutes(router, routeConfigs) {\n  for (const config of routeConfigs) {\n    const { method, path, middleware = [], validate, handler, cache } = config;\n    const chain = [];\n    if (middleware.length) chain.push(...middleware);\n    if (validate) chain.push(createValidator(validate));\n    if (cache) chain.push(cacheMiddleware(cache));\n    chain.push(wrapAsync(handler));\n    router[method.toLowerCase()](path, ...chain);\n  }\n  return router;\n}\nfunction wrapAsync(fn) {\n  return (req, res, next) => Promise.resolve(fn(req, res, next)).catch(next);\n}\nconst routes = [\n  { method:'GET', path:'/users', handler: async (req,res) => res.json(await db.user.findMany()) },\n  { method:'POST', path:'/users', middleware:[requireAuth], validate:{name:'required|string',email:'required|email'}, handler: async (req,res) => res.status(201).json(await db.user.create({data:req.body})) },\n  { method:'DELETE', path:'/users/:id', middleware:[requireAuth,requireRole('admin')], handler: async (req,res) => { await db.user.delete({where:{id:+req.params.id}}); res.status(204).end(); } }\n];\ngenerateRoutes(router, routes);",hints:"wrapAsync catches promise rejections and forwards to Express error handler. Route config is data - generates middleware chain programmatically.",solutionExplanation:"Config-driven routing enables consistent patterns across all routes. wrapAsync eliminates try/catch in every async handler."},

  // Lesson 46 - Express Middleware coding
  {lessonId:46,difficulty:"Easy",title:"Request ID Middleware",problemStatement:"Build middleware that assigns a unique request ID to each request via x-request-id header. Use the incoming header if present, else generate one.",examples:"Each request gets req.id. Response includes X-Request-ID header.",starterCodeJs:"const { randomUUID } = require('crypto');\nfunction requestId(options = {}) {\n  const { header = 'x-request-id', generator = randomUUID, setHeader = true } = options;\n  return (req, res, next) => {\n    const id = req.headers[header] || generator();\n    req.id = id;\n    req.requestId = id; // alias\n    if (setHeader) res.setHeader('X-Request-ID', id);\n    next();\n  };\n}\nmodule.exports = requestId;\n// Usage: app.use(requestId())",hints:"Respect incoming x-request-id from load balancers/other services. Set on both req and response header. crypto.randomUUID() is the modern standard.",solutionExplanation:"Request IDs enable distributed tracing. Accept upstream IDs to maintain trace across services. randomUUID() generates RFC 4122 UUID v4."},
  {lessonId:46,difficulty:"Medium",title:"Input Sanitization Middleware",problemStatement:"Build middleware that sanitizes req.body, req.query, and req.params to prevent XSS. Strip HTML tags and trim whitespace.",examples:"<script>alert(1)</script> in body becomes 'alert(1)'. Trim whitespace from all string values.",starterCodeJs:"function sanitize(value) {\n  if (typeof value !== 'string') return value;\n  return value\n    .replace(/<script\\b[^<]*(?:(?!<\\/script>)<[^<]*)*<\\/script>/gi, '')\n    .replace(/<[^>]+>/g, '')\n    .replace(/&lt;/g,'<').replace(/&gt;/g,'>').replace(/&amp;/g,'&')\n    .trim();\n}\nfunction sanitizeObj(obj) {\n  if (!obj || typeof obj !== 'object') return obj;\n  const result = {};\n  for (const [key, value] of Object.entries(obj)) {\n    if (Array.isArray(value)) result[key] = value.map(v => typeof v === 'object' ? sanitizeObj(v) : sanitize(v));\n    else if (typeof value === 'object') result[key] = sanitizeObj(value);\n    else result[key] = sanitize(value);\n  }\n  return result;\n}\nfunction sanitizeInput(req, res, next) {\n  req.body = sanitizeObj(req.body);\n  req.query = sanitizeObj(req.query);\n  req.params = sanitizeObj(req.params);\n  next();\n}",hints:"Recursively handle nested objects and arrays. Strip script tags first, then all HTML. This is defense-in-depth; also escape on output.",solutionExplanation:"Input sanitization removes dangerous content. Defense-in-depth: sanitize input AND escape output. Libraries like DOMPurify are more thorough."},
  {lessonId:46,difficulty:"Medium",title:"API Key Authentication",problemStatement:"Build API key middleware that validates keys from x-api-key header or query param. Support key rotation (old and new keys).",examples:"x-api-key: sk_live_abc123 -> valid. Missing key -> 401. Invalid -> 403.",starterCodeJs:"const VALID_KEYS = new Map([\n  ['sk_live_abc123', { owner: 'client-1', scopes: ['read','write'], active: true }],\n  ['sk_live_xyz789', { owner: 'client-2', scopes: ['read'], active: true }],\n  ['sk_old_key', { owner: 'client-1', scopes: ['read'], active: false }] // rotated\n]);\nfunction apiKeyAuth(req, res, next) {\n  const key = req.headers['x-api-key'] || req.query.api_key;\n  if (!key) return res.status(401).json({ error: 'API key required' });\n  const keyInfo = VALID_KEYS.get(key);\n  if (!keyInfo) return res.status(403).json({ error: 'Invalid API key' });\n  if (!keyInfo.active) return res.status(403).json({ error: 'API key has been revoked' });\n  req.apiKey = { key, ...keyInfo };\n  delete req.query.api_key; // don't expose in logs\n  next();\n}\nfunction requireScope(scope) {\n  return (req, res, next) => {\n    if (!req.apiKey?.scopes.includes(scope)) return res.status(403).json({ error: `Requires ${scope} scope` });\n    next();\n  };\n}",hints:"Accept key from header or query param. Separate 401 (no key) from 403 (bad key). Remove api_key from query to prevent logging sensitive data.",solutionExplanation:"API key auth: 401 for missing (unauthenticated), 403 for invalid (unauthorized). Scope-based permissions for fine-grained access control."},
  {lessonId:46,difficulty:"Hard",title:"Circuit Breaker Middleware",problemStatement:"Implement circuit breaker pattern for external API calls. States: CLOSED (normal), OPEN (failing, reject fast), HALF_OPEN (testing recovery).",examples:"5 failures in 60s -> OPEN. After 30s -> HALF_OPEN (1 probe). Success -> CLOSED. Fail -> OPEN.",starterCodeJs:"class CircuitBreaker {\n  constructor({ threshold=5, timeout=60000, halfOpenTimeout=30000 } = {}) {\n    this.state = 'CLOSED';\n    this.failures = 0;\n    this.threshold = threshold;\n    this.lastFailure = 0;\n    this.timeout = timeout;\n    this.halfOpenTimeout = halfOpenTimeout;\n  }\n  async call(fn) {\n    if (this.state === 'OPEN') {\n      if (Date.now() - this.lastFailure > this.halfOpenTimeout) this.state = 'HALF_OPEN';\n      else throw new Error('Circuit breaker is OPEN');\n    }\n    try {\n      const result = await fn();\n      if (this.state === 'HALF_OPEN') { this.state = 'CLOSED'; this.failures = 0; }\n      return result;\n    } catch (err) {\n      this.failures++;\n      this.lastFailure = Date.now();\n      if (this.failures >= this.threshold || this.state === 'HALF_OPEN') this.state = 'OPEN';\n      throw err;\n    }\n  }\n}\n// Express middleware wrapping external call:\nconst breaker = new CircuitBreaker();\nfunction withCircuitBreaker(req, res, next) {\n  breaker.call(() => externalApiCall(req))\n    .then(data => { req.externalData = data; next(); })\n    .catch(err => res.status(503).json({ error: err.message }));\n}",hints:"OPEN: reject immediately. After timeout, try HALF_OPEN (one probe). Success -> CLOSED. Failure -> back to OPEN. Reset failure count on CLOSED.",solutionExplanation:"Circuit breaker prevents cascade failures. OPEN state gives downstream service time to recover. HALF_OPEN probes recovery. Metric: failure threshold."},
  {lessonId:46,difficulty:"Easy",title:"CORS Configuration Middleware",problemStatement:"Build configurable CORS middleware. Support origin whitelist, credential handling, preflight OPTIONS requests, and per-route CORS.",examples:"cors({origins:['https://app.com']}) allows only that origin. Preflight -> 204.",starterCodeJs:"function cors(options = {}) {\n  const { origins = '*', methods = 'GET,POST,PUT,PATCH,DELETE,OPTIONS', headers = 'Content-Type,Authorization,X-Request-ID', credentials = false, maxAge = 86400 } = options;\n  return (req, res, next) => {\n    const origin = req.headers.origin;\n    let allowOrigin = '*';\n    if (Array.isArray(origins)) {\n      allowOrigin = origins.includes(origin) ? origin : '';\n    } else if (typeof origins === 'function') {\n      allowOrigin = origins(origin) ? origin : '';\n    } else if (origins !== '*') {\n      allowOrigin = origins;\n    }\n    if (allowOrigin) res.setHeader('Access-Control-Allow-Origin', allowOrigin);\n    if (credentials) res.setHeader('Access-Control-Allow-Credentials', 'true');\n    if (req.method === 'OPTIONS') {\n      res.setHeader('Access-Control-Allow-Methods', methods);\n      res.setHeader('Access-Control-Allow-Headers', headers);\n      res.setHeader('Access-Control-Max-Age', maxAge);\n      return res.status(204).end();\n    }\n    next();\n  };\n}",hints:"Reflect origin back when using credentials (wildcard doesn't work with credentials). Handle OPTIONS preflight separately. Max-Age caches preflight result.",solutionExplanation:"CORS headers: Allow-Origin required for all cross-origin. Allow-Credentials needs explicit origin (not *). OPTIONS preflight returns 204 with allowed methods/headers."},
  {lessonId:46,difficulty:"Medium",title:"Response Transformer Middleware",problemStatement:"Build middleware that transforms all JSON responses to a consistent envelope format: {success, data, error, meta:{requestId, timestamp, duration}}.",examples:"res.json({name:'Alice'}) becomes {success:true, data:{name:'Alice'}, meta:{requestId:'abc', timestamp:'...', duration:45}}",starterCodeJs:"function responseTransformer(req, res, next) {\n  const start = Date.now();\n  const origJson = res.json.bind(res);\n  res.json = function(body) {\n    const isError = res.statusCode >= 400;\n    const envelope = {\n      success: !isError,\n      data: isError ? null : body,\n      error: isError ? body : null,\n      meta: {\n        requestId: req.id || req.requestId,\n        timestamp: new Date().toISOString(),\n        duration: Date.now() - start\n      }\n    };\n    return origJson.call(this, envelope);\n  };\n  next();\n}\n// Skip for specific routes:\nfunction noEnvelope(req, res, next) {\n  res.rawJson = res.json.bind(res);\n  next();\n}",hints:"Wrap res.json before calling next(). Check statusCode for error vs success. Don't forget to call original json with correct this context.",solutionExplanation:"Consistent API envelope: consumers always check success field, find data or error in known locations. Duration helps identify slow endpoints."},
  {lessonId:46,difficulty:"Hard",title:"Request Deduplication",problemStatement:"Build middleware that deduplicates identical concurrent POST requests using an idempotency key. Return cached response for duplicate requests.",examples:"POST /payments with Idempotency-Key: pay_123 -> process once. Second request with same key within 24h -> return first result.",starterCodeJs:"const pendingRequests = new Map();\nconst completedRequests = new Map();\nconst TTL = 24 * 60 * 60 * 1000;\nfunction idempotency(req, res, next) {\n  if (!['POST','PUT','PATCH'].includes(req.method)) return next();\n  const key = req.headers['idempotency-key'];\n  if (!key) return next();\n  // Already completed\n  const completed = completedRequests.get(key);\n  if (completed && Date.now() < completed.exp) {\n    return res.status(completed.status).set('X-Idempotent-Replayed','true').json(completed.body);\n  }\n  // Currently in flight\n  if (pendingRequests.has(key)) {\n    return pendingRequests.get(key).then(result => res.status(result.status).json(result.body)).catch(() => res.status(503).json({error:'Request in progress'}));\n  }\n  const origJson = res.json.bind(res);\n  let resolve;\n  const promise = new Promise(r => { resolve = r; });\n  pendingRequests.set(key, promise);\n  res.json = body => {\n    const result = { body, status: res.statusCode, exp: Date.now() + TTL };\n    completedRequests.set(key, result);\n    pendingRequests.delete(key);\n    resolve(result);\n    return origJson(body);\n  };\n  next();\n}",hints:"Two maps: pending (in-flight) and completed (cached). Pending requests wait on a Promise. Completed requests return cached response immediately.",solutionExplanation:"Idempotency keys prevent double charges/actions. Pending map handles concurrent duplicates. 24h TTL covers network retries. Required for payment APIs."},
  {lessonId:46,difficulty:"Easy",title:"Async Error Handler",problemStatement:"Build an asyncHandler wrapper and global error handler for Express. The error handler should return JSON errors with appropriate status codes.",examples:"router.get('/', asyncHandler(async(req,res) => { ... })). Errors auto-forwarded to global handler.",starterCodeJs:"function asyncHandler(fn) {\n  return (req, res, next) => Promise.resolve(fn(req, res, next)).catch(next);\n}\nclass AppError extends Error {\n  constructor(message, statusCode = 500, code = 'INTERNAL_ERROR') {\n    super(message);\n    this.statusCode = statusCode;\n    this.code = code;\n    this.isOperational = true;\n  }\n}\nfunction globalErrorHandler(err, req, res, next) {\n  const statusCode = err.statusCode || (err.name === 'ValidationError' ? 400 : err.name === 'UnauthorizedError' ? 401 : 500);\n  const response = {\n    error: { message: err.message, code: err.code || 'INTERNAL_ERROR', ...(process.env.NODE_ENV === 'development' && { stack: err.stack }) }\n  };\n  if (!err.isOperational) console.error('Unexpected error:', err);\n  res.status(statusCode).json(response);\n}\nmodule.exports = { asyncHandler, AppError, globalErrorHandler };",hints:"asyncHandler: Promise.resolve(fn()).catch(next) - works for both sync and async. AppError.isOperational distinguishes expected vs unexpected errors.",solutionExplanation:"asyncHandler eliminates try/catch in every async route. AppError for expected errors (validation, 404). Unhandled errors logged as bugs."},
  {lessonId:46,difficulty:"Medium",title:"Request Body Size Limiter",problemStatement:"Build middleware that rejects requests with body size exceeding a limit. Support different limits per route and return 413 with clear error.",examples:"bodySizeLimit('1mb') rejects bodies over 1MB with 413 Payload Too Large.",starterCodeJs:"function parseSize(size) {\n  if (typeof size === 'number') return size;\n  const units = { b: 1, kb: 1024, mb: 1024**2, gb: 1024**3 };\n  const match = String(size).toLowerCase().match(/^(\\d+)\\s*(b|kb|mb|gb)$/);\n  if (!match) throw new Error(`Invalid size: ${size}`);\n  return parseInt(match[1]) * units[match[2]];\n}\nfunction bodySizeLimit(limit) {\n  const maxBytes = parseSize(limit);\n  return (req, res, next) => {\n    const contentLength = parseInt(req.headers['content-length']);\n    if (contentLength > maxBytes) {\n      return res.status(413).json({\n        error: 'Payload Too Large',\n        maxSize: limit,\n        received: `${(contentLength/1024/1024).toFixed(2)}MB`\n      });\n    }\n    let bytes = 0;\n    req.on('data', chunk => {\n      bytes += chunk.length;\n      if (bytes > maxBytes) {\n        req.destroy();\n        res.status(413).json({ error: 'Payload Too Large' });\n      }\n    });\n    next();\n  };\n}",hints:"Check Content-Length header first (fast path). Also stream-count for chunked transfers without Content-Length. req.destroy() aborts.",solutionExplanation:"Two-layer check: Content-Length header (fast) and streaming count (handles chunked). 413 status is the correct code for oversized payloads."},

  // Lesson 47 - REST API Design coding
  {lessonId:47,difficulty:"Easy",title:"RESTful API Conventions",problemStatement:"Build a RESTful users API that follows all conventions: proper HTTP methods, status codes, error format, pagination, and response envelope.",examples:"GET /users?page=1&limit=10 -> 200. POST /users -> 201. DELETE /users/1 -> 204. Not found -> 404.",starterCodeJs:"const router = require('express').Router();\nconst db = require('../db');\nrouter.get('/', async (req, res) => {\n  const page = Math.max(1, parseInt(req.query.page) || 1);\n  const limit = Math.min(100, parseInt(req.query.limit) || 20);\n  const [users, total] = await Promise.all([db.user.findMany({skip:(page-1)*limit,take:limit}), db.user.count()]);\n  res.json({ data: users, pagination: { page, limit, total, pages: Math.ceil(total/limit), hasNext: page*limit < total, hasPrev: page > 1 } });\n});\nrouter.post('/', async (req, res) => {\n  const { name, email } = req.body;\n  if (!name || !email) return res.status(400).json({ error: { code:'VALIDATION_ERROR', fields: { name:!name?'required':null, email:!email?'required':null } } });\n  const user = await db.user.create({ data: { name, email } });\n  res.status(201).location(`/api/users/${user.id}`).json(user);\n});\nrouter.delete('/:id', async (req, res) => {\n  const user = await db.user.findUnique({ where: { id: parseInt(req.params.id) } });\n  if (!user) return res.status(404).json({ error: { code:'NOT_FOUND', message:'User not found' } });\n  await db.user.delete({ where: { id: user.id } });\n  res.status(204).end();\n});",hints:"201 Created with Location header for POST. 204 No Content for DELETE. 400 with field-level errors for validation. hasPrev/hasNext for pagination UX.",solutionExplanation:"REST conventions: status codes match the action result. Location header after 201. Consistent error format with code. Pagination meta helps clients."},
  {lessonId:47,difficulty:"Medium",title:"HATEOAS Implementation",problemStatement:"Add hypermedia links to API responses. Each user resource should include links for self, edit, delete, and related resources (posts).",examples:"GET /users/1 -> {id:1, name:'Alice', _links:{self:{href:'/users/1'}, posts:{href:'/users/1/posts'}}}",starterCodeJs:"function addLinks(resource, resourceType, req) {\n  const base = `${req.protocol}://${req.get('host')}/api`;\n  const links = {};\n  switch (resourceType) {\n    case 'user':\n      links.self = { href: `${base}/users/${resource.id}`, method: 'GET' };\n      links.update = { href: `${base}/users/${resource.id}`, method: 'PUT' };\n      links.delete = { href: `${base}/users/${resource.id}`, method: 'DELETE' };\n      links.posts = { href: `${base}/users/${resource.id}/posts`, method: 'GET' };\n      break;\n    case 'post':\n      links.self = { href: `${base}/posts/${resource.id}`, method: 'GET' };\n      links.author = { href: `${base}/users/${resource.authorId}`, method: 'GET' };\n      links.comments = { href: `${base}/posts/${resource.id}/comments`, method: 'GET' };\n      break;\n  }\n  return { ...resource, _links: links };\n}\nrouter.get('/users/:id', async (req, res) => {\n  const user = await db.user.findUnique({ where: { id: parseInt(req.params.id) } });\n  if (!user) return res.status(404).json({ error: 'Not found' });\n  res.json(addLinks(user, 'user', req));\n});",hints:"HATEOAS links tell clients what actions are available without hardcoding URLs. Include HTTP method with each link.",solutionExplanation:"HATEOAS makes APIs self-discoverable. Clients follow links rather than constructing URLs. Reduces coupling between client and server URL structure."},
  {lessonId:47,difficulty:"Medium",title:"API Error Response Standard",problemStatement:"Build a standardized error response system following RFC 7807 (Problem Details). Include type, title, status, detail, and instance fields.",examples:"404 -> {type:'about:blank', title:'Not Found', status:404, detail:'User 42 not found', instance:'/users/42'}",starterCodeJs:"const PROBLEM_TYPES = {\n  NOT_FOUND: { type: 'https://api.example.com/problems/not-found', title: 'Not Found' },\n  VALIDATION_ERROR: { type: 'https://api.example.com/problems/validation-error', title: 'Validation Error' },\n  UNAUTHORIZED: { type: 'https://api.example.com/problems/unauthorized', title: 'Unauthorized' },\n  FORBIDDEN: { type: 'https://api.example.com/problems/forbidden', title: 'Forbidden' },\n  CONFLICT: { type: 'https://api.example.com/problems/conflict', title: 'Conflict' },\n};\nfunction problemDetail(type, status, detail, extra = {}) {\n  const base = PROBLEM_TYPES[type] || { type: 'about:blank', title: 'Error' };\n  return { ...base, status, detail, ...extra };\n}\nfunction errorHandler(err, req, res, next) {\n  res.setHeader('Content-Type', 'application/problem+json');\n  if (err.statusCode === 404) return res.status(404).json(problemDetail('NOT_FOUND', 404, err.message, { instance: req.path }));\n  if (err.statusCode === 400) return res.status(400).json(problemDetail('VALIDATION_ERROR', 400, err.message, { errors: err.errors }));\n  res.status(500).json(problemDetail('SERVER_ERROR', 500, 'An unexpected error occurred', { instance: req.path }));\n}",hints:"Content-Type: application/problem+json signals RFC 7807 format. instance field is the specific request URL. type should be a URL pointing to documentation.",solutionExplanation:"RFC 7807 standardizes error responses. Machines read status+type; humans read title+detail. Consistent format across all endpoints."},
  {lessonId:47,difficulty:"Hard",title:"Bulk Operations Endpoint",problemStatement:"Build a bulk endpoint POST /users/bulk that accepts an array of operations (create/update/delete). Return per-operation results with success/failure.",examples:"POST /users/bulk [{op:'create',data:{...}},{op:'delete',id:5}] -> [{success:true,...},{success:false,error:'...'}]",starterCodeJs:"router.post('/bulk', async (req, res) => {\n  const { operations } = req.body;\n  if (!Array.isArray(operations) || operations.length > 100) {\n    return res.status(400).json({ error: 'operations must be array of max 100 items' });\n  }\n  const results = await Promise.allSettled(\n    operations.map(async (op, index) => {\n      switch (op.op) {\n        case 'create': return db.user.create({ data: op.data });\n        case 'update': return db.user.update({ where: { id: op.id }, data: op.data });\n        case 'delete': return db.user.delete({ where: { id: op.id } });\n        default: throw new Error(`Unknown op: ${op.op}`);\n      }\n    })\n  );\n  const response = results.map((r, i) => r.status === 'fulfilled'\n    ? { index: i, success: true, data: r.value }\n    : { index: i, success: false, error: r.reason?.message }\n  );\n  const allSucceeded = response.every(r => r.success);\n  res.status(allSucceeded ? 200 : 207).json({ results: response });\n});",hints:"Promise.allSettled returns results for all regardless of failure. 207 Multi-Status when mixed success/failure. Cap at 100 operations.",solutionExplanation:"Bulk API reduces round trips. Promise.allSettled (not Promise.all) continues despite individual failures. 207 signals mixed results to clients."},
  {lessonId:47,difficulty:"Medium",title:"API Documentation Endpoint",problemStatement:"Build a self-documenting API that generates route documentation from registered routes. GET /api/docs returns all routes with methods, paths, and descriptions.",examples:"GET /api/docs -> {routes:[{method:'GET',path:'/users',description:'List all users'},...]}",starterCodeJs:"const routes = [];\nfunction doc(description, tags = []) {\n  return (req, res, next) => next(); // passthrough, metadata attached below\n}\nfunction documentedRoute(router, method, path, description, ...handlers) {\n  routes.push({ method: method.toUpperCase(), path, description, tags: [] });\n  router[method.toLowerCase()](path, ...handlers);\n}\nfunction addDocsEndpoint(app) {\n  app.get('/api/docs', (req, res) => {\n    const grouped = routes.reduce((acc, route) => {\n      const resource = route.path.split('/')[1] || 'root';\n      if (!acc[resource]) acc[resource] = [];\n      acc[resource].push(route);\n      return acc;\n    }, {});\n    res.json({ version: '1.0.0', routes, grouped, generatedAt: new Date().toISOString() });\n  });\n}\n// Usage:\ndocumentedRoute(router, 'get', '/users', 'List all users with pagination');\ndocumentedRoute(router, 'post', '/users', 'Create a new user');",hints:"Store route metadata in array at registration time. Group by resource (first path segment). This is manual OpenAPI-lite.",solutionExplanation:"Self-documenting API: register metadata alongside route. For full OpenAPI, use swagger-jsdoc or tsoa which generate spec from JSDoc/TypeScript."},
  {lessonId:47,difficulty:"Easy",title:"Content Negotiation",problemStatement:"Build an endpoint that responds with different formats based on Accept header: JSON (default), XML, or CSV for user list.",examples:"Accept: application/json -> JSON. Accept: text/csv -> CSV. Accept: application/xml -> XML.",starterCodeJs:"const router = require('express').Router();\nfunction toCSV(users) {\n  const headers = ['id','name','email'].join(',');\n  const rows = users.map(u => [u.id, u.name, u.email].join(','));\n  return [headers, ...rows].join('\\n');\n}\nfunction toXML(users) {\n  const items = users.map(u => `  <user><id>${u.id}</id><name>${u.name}</name><email>${u.email}</email></user>`).join('\\n');\n  return `<?xml version=\"1.0\"?>\\n<users>\\n${items}\\n</users>`;\n}\nrouter.get('/users', async (req, res) => {\n  const users = await db.user.findMany();\n  const accept = req.headers.accept || 'application/json';\n  if (accept.includes('text/csv')) {\n    return res.set('Content-Type','text/csv').set('Content-Disposition','attachment; filename=users.csv').send(toCSV(users));\n  }\n  if (accept.includes('application/xml')) {\n    return res.set('Content-Type','application/xml').send(toXML(users));\n  }\n  res.json(users); // default JSON\n});",hints:"Check Accept header for content type. CSV needs Content-Disposition for download. XML needs proper header.",solutionExplanation:"Content negotiation: same resource, different representations. Accept header drives format. res.format() is Express's built-in content negotiation helper."},
  {lessonId:47,difficulty:"Hard",title:"GraphQL-style Field Selection",problemStatement:"Build a REST endpoint that supports field selection via fields query param, reducing response payload.",examples:"GET /users?fields=id,name -> only id and name in response. Default returns all fields.",starterCodeJs:"function selectFields(obj, fields) {\n  if (!fields || !fields.length) return obj;\n  if (Array.isArray(obj)) return obj.map(item => selectFields(item, fields));\n  return fields.reduce((acc, field) => { if (field in obj) acc[field] = obj[field]; return acc; }, {});\n}\nfunction fieldSelection(req, res, next) {\n  const fields = req.query.fields ? req.query.fields.split(',').map(f => f.trim()) : null;\n  if (!fields) return next();\n  const origJson = res.json.bind(res);\n  res.json = (body) => {\n    const data = body?.data || body;\n    const selected = selectFields(data, fields);\n    const result = body?.data ? { ...body, data: selected } : selected;\n    return origJson(result);\n  };\n  next();\n}\n// Usage: router.get('/users', fieldSelection, listUsersHandler)",hints:"Parse fields from query param. Intercept res.json to filter fields. Handle both direct array and envelope {data:[...]} responses.",solutionExplanation:"Field selection reduces payload size (useful for mobile). Applied as middleware so any route can opt in. Intercept res.json to filter before sending."},
  {lessonId:47,difficulty:"Medium",title:"Cursor-based Pagination",problemStatement:"Implement cursor-based pagination (better than offset for large datasets). GET /posts with cursor returns next page cursor in response.",examples:"GET /posts?limit=10 -> {data:[...],nextCursor:'abc123'}. GET /posts?cursor=abc123&limit=10 -> next page.",starterCodeJs:"router.get('/posts', async (req, res) => {\n  const limit = Math.min(100, parseInt(req.query.limit) || 20);\n  const cursor = req.query.cursor;\n  let cursorWhere = {};\n  if (cursor) {\n    const decoded = JSON.parse(Buffer.from(cursor, 'base64url').toString());\n    cursorWhere = { createdAt: { lt: new Date(decoded.createdAt) }, id: { lt: decoded.id } };\n  }\n  const posts = await db.post.findMany({\n    where: cursorWhere,\n    orderBy: [{ createdAt: 'desc' }, { id: 'desc' }],\n    take: limit + 1 // fetch one extra to detect hasMore\n  });\n  const hasMore = posts.length > limit;\n  const items = hasMore ? posts.slice(0, limit) : posts;\n  const lastItem = items[items.length - 1];\n  const nextCursor = hasMore && lastItem\n    ? Buffer.from(JSON.stringify({ createdAt: lastItem.createdAt, id: lastItem.id })).toString('base64url')\n    : null;\n  res.json({ data: items, nextCursor, hasMore });\n});",hints:"Fetch limit+1 to detect hasMore without extra count query. Cursor = base64url-encoded last item ID+timestamp. Stable sort by both timestamp and ID.",solutionExplanation:"Cursor pagination: stable under inserts (offset shifts). Take limit+1 to check hasMore. Encode cursor as opaque string (clients don't need to understand it)."},

  // Lesson 48 - Express Advanced coding
  {lessonId:48,difficulty:"Easy",title:"Server-Sent Events",problemStatement:"Build a Server-Sent Events endpoint in Express that streams real-time updates to the browser. Clients receive events when data changes.",examples:"GET /api/events -> event stream. Browser: new EventSource('/api/events'). Sends event every second.",starterCodeJs:"const clients = new Set();\nfunction sseMiddleware(req, res) {\n  res.setHeader('Content-Type', 'text/event-stream');\n  res.setHeader('Cache-Control', 'no-cache');\n  res.setHeader('Connection', 'keep-alive');\n  res.setHeader('Access-Control-Allow-Origin', '*');\n  res.flushHeaders();\n  const sendEvent = (data, event = 'message', id = Date.now()) => {\n    res.write(`id: ${id}\\nevent: ${event}\\ndata: ${JSON.stringify(data)}\\n\\n`);\n  };\n  clients.add(sendEvent);\n  req.on('close', () => clients.delete(sendEvent));\n  sendEvent({ type: 'connected', time: new Date().toISOString() }, 'connected');\n}\nfunction broadcast(data, event = 'message') {\n  clients.forEach(send => send(data, event));\n}\nrouter.get('/events', sseMiddleware);\nconst interval = setInterval(() => broadcast({ time: new Date().toISOString(), clients: clients.size }), 1000);\nmodule.exports = { router, broadcast };",hints:"SSE format: 'data: ...\\n\\n'. setHeader before any write. flushHeaders starts the stream. req.on('close') detects disconnect.",solutionExplanation:"SSE is simpler than WebSocket for server-to-client streaming. Browser reconnects automatically. Good for live feeds, progress, notifications."},
  {lessonId:48,difficulty:"Medium",title:"Background Job Queue",problemStatement:"Build an Express endpoint that queues long-running jobs and returns a job ID. Clients poll GET /jobs/:id for status and result.",examples:"POST /jobs {type:'export'} -> {jobId:'123'}. GET /jobs/123 -> {status:'completed', result:{...}}",starterCodeJs:"const jobs = new Map();\nlet jobCounter = 1;\nconst workers = { 'export': exportData, 'report': generateReport };\nasync function exportData(params) {\n  await new Promise(r => setTimeout(r, 2000)); // simulate work\n  return { rows: 1000, file: 'export.csv' };\n}\nasync function generateReport(params) {\n  await new Promise(r => setTimeout(r, 3000));\n  return { pages: 5, file: 'report.pdf' };\n}\nrouter.post('/jobs', (req, res) => {\n  const { type, params } = req.body;\n  if (!workers[type]) return res.status(400).json({ error: `Unknown job type: ${type}` });\n  const jobId = String(jobCounter++);\n  jobs.set(jobId, { id: jobId, type, status: 'pending', createdAt: new Date().toISOString() });\n  workers[type](params).then(result => jobs.get(jobId) && jobs.set(jobId, { ...jobs.get(jobId), status:'completed', result, completedAt: new Date().toISOString() })).catch(err => jobs.set(jobId, { ...jobs.get(jobId), status:'failed', error: err.message }));\n  res.status(202).json({ jobId, status: 'pending' });\n});\nrouter.get('/jobs/:id', (req, res) => {\n  const job = jobs.get(req.params.id);\n  job ? res.json(job) : res.status(404).json({ error: 'Job not found' });\n});",hints:"202 Accepted (not 201) for async operations. Store job state in Map. Worker runs async without awaiting in request handler.",solutionExplanation:"Background jobs: return 202 immediately, process async. Client polls for completion. 202 means 'accepted for processing, not yet done'."},
  {lessonId:48,difficulty:"Hard",title:"HTTP Response Compression",problemStatement:"Implement response compression middleware that gzip/deflate/brotli compresses responses based on Accept-Encoding header.",examples:"Accept-Encoding: br,gzip -> brotli. Accept-Encoding: gzip -> gzip. No support -> no compression.",starterCodeJs:"const zlib = require('zlib');\nconst { pipeline } = require('stream/promises');\nconst { Readable } = require('stream');\nfunction compression(options = {}) {\n  const { threshold = 1024 } = options;\n  return (req, res, next) => {\n    const accept = req.headers['accept-encoding'] || '';\n    let encoder, encoding;\n    if (accept.includes('br')) { encoder = zlib.createBrotliCompress(); encoding = 'br'; }\n    else if (accept.includes('gzip')) { encoder = zlib.createGzip(); encoding = 'gzip'; }\n    else if (accept.includes('deflate')) { encoder = zlib.createDeflate(); encoding = 'deflate'; }\n    else return next();\n    const origSend = res.send.bind(res);\n    res.send = function(body) {\n      const buf = Buffer.isBuffer(body) ? body : Buffer.from(body);\n      if (buf.length < threshold) return origSend.call(this, body);\n      zlib.brotliCompress(buf, (err, compressed) => {\n        if (err) return origSend.call(this, body);\n        res.setHeader('Content-Encoding', encoding);\n        res.removeHeader('Content-Length');\n        origSend.call(this, compressed);\n      });\n    };\n    next();\n  };\n}",hints:"Check Accept-Encoding header for supported algorithms. Prefer brotli > gzip > deflate. Don't compress small responses (overhead not worth it).",solutionExplanation:"Compression reduces transfer size 60-80%. Threshold avoids overhead for tiny responses. Remove Content-Length since compressed size differs."},
  {lessonId:48,difficulty:"Medium",title:"Webhook Sender with Retry",problemStatement:"Build a webhook delivery service that sends HTTP callbacks with retry logic (exponential backoff) and signature verification.",examples:"deliverWebhook(url, event) -> POSTs signed payload, retries up to 3 times with backoff.",starterCodeJs:"const crypto = require('crypto');\nconst https = require('https');\nasync function deliverWebhook(url, event, secret, options = {}) {\n  const { maxRetries = 3, timeout = 5000 } = options;\n  const payload = JSON.stringify({ event, timestamp: Date.now() });\n  const signature = crypto.createHmac('sha256', secret).update(payload).digest('hex');\n  for (let attempt = 1; attempt <= maxRetries; attempt++) {\n    try {\n      const controller = new AbortController();\n      const timer = setTimeout(() => controller.abort(), timeout);\n      const res = await fetch(url, {\n        method: 'POST',\n        headers: { 'Content-Type': 'application/json', 'X-Webhook-Signature': `sha256=${signature}`, 'X-Webhook-Attempt': String(attempt) },\n        body: payload,\n        signal: controller.signal\n      });\n      clearTimeout(timer);\n      if (res.ok) return { success: true, attempt, status: res.status };\n      if (res.status < 500) return { success: false, reason: `Client error ${res.status}`, attempt };\n    } catch (err) { if (attempt === maxRetries) return { success: false, reason: err.message, attempt }; }\n    await new Promise(r => setTimeout(r, Math.min(1000 * 2 ** attempt, 30000) + Math.random() * 1000));\n  }\n}",hints:"HMAC signature lets receiver verify authenticity. Exponential backoff: 2s, 4s, 8s... Don't retry 4xx errors (client error, retrying won't help).",solutionExplanation:"Webhook reliability: HMAC-SHA256 signature for authenticity. Exponential backoff avoids hammering failing endpoints. Skip retry on 4xx."},
  {lessonId:48,difficulty:"Easy",title:"Health Check Endpoint",problemStatement:"Build a comprehensive health check endpoint that checks database connectivity, memory usage, and uptime. Returns detailed status.",examples:"GET /health -> {status:'healthy', db:'connected', memoryMB:45, uptimeSeconds:3600}",starterCodeJs:"const os = require('os');\nrouter.get('/health', async (req, res) => {\n  const checks = {};\n  let allHealthy = true;\n  // DB check\n  try { await db.$queryRaw`SELECT 1`; checks.database = { status:'healthy' }; }\n  catch (e) { checks.database = { status:'unhealthy', error: e.message }; allHealthy = false; }\n  // Memory check\n  const used = process.memoryUsage();\n  const heapPercent = (used.heapUsed / used.heapTotal) * 100;\n  checks.memory = { heapUsedMB: Math.round(used.heapUsed/1024/1024), heapTotalMB: Math.round(used.heapTotal/1024/1024), heapPercent: Math.round(heapPercent), status: heapPercent > 90 ? 'warning' : 'healthy' };\n  if (heapPercent > 95) allHealthy = false;\n  // Uptime\n  checks.uptime = { seconds: Math.round(process.uptime()), os: Math.round(os.uptime()) };\n  const status = allHealthy ? 'healthy' : 'unhealthy';\n  res.status(allHealthy ? 200 : 503).json({ status, checks, version: process.env.npm_package_version, timestamp: new Date().toISOString() });\n});",hints:"503 Service Unavailable when unhealthy (load balancers remove unhealthy instances). Check DB, memory, disk space as appropriate.",solutionExplanation:"Health checks enable load balancer auto-removal of failing instances. Return 503 (not 200) on unhealthy so ALBs/k8s stop routing traffic."},

  // Lesson 49 - SQL Databases coding
  {lessonId:49,difficulty:"Easy",title:"SQL Query Builder",problemStatement:"Write SQL queries for: find users by email, get posts with author info (JOIN), count posts per user (GROUP BY), get top 10 users by post count.",examples:"SELECT users.*, COUNT(posts.id) as post_count FROM users LEFT JOIN posts ON ...",starterCodeJs:"// Find user by email\nconst findByEmail = `SELECT id, name, email, role, created_at FROM users WHERE email = ? LIMIT 1`;\n// Get posts with author info\nconst postsWithAuthor = `\n  SELECT posts.*, users.name as author_name, users.email as author_email\n  FROM posts\n  INNER JOIN users ON posts.author_id = users.id\n  WHERE posts.published = 1\n  ORDER BY posts.created_at DESC\n  LIMIT ? OFFSET ?\n`;\n// Count posts per user\nconst postCountPerUser = `\n  SELECT users.id, users.name, COUNT(posts.id) as post_count\n  FROM users\n  LEFT JOIN posts ON posts.author_id = users.id\n  GROUP BY users.id, users.name\n  ORDER BY post_count DESC\n`;\n// Top 10 most active users\nconst top10Users = `\n  SELECT u.id, u.name, COUNT(DISTINCT p.id) as posts, COUNT(DISTINCT c.id) as comments\n  FROM users u\n  LEFT JOIN posts p ON p.author_id = u.id\n  LEFT JOIN comments c ON c.author_id = u.id\n  GROUP BY u.id, u.name\n  ORDER BY posts + comments DESC\n  LIMIT 10\n`;",hints:"LEFT JOIN includes users with no posts (COUNT is 0). INNER JOIN would exclude them. COUNT(DISTINCT id) avoids counting duplicates from multiple joins.",solutionExplanation:"JOIN types matter: LEFT keeps all from left table. INNER requires match in both. GROUP BY + COUNT = aggregation per group. HAVING filters groups (WHERE filters rows)."},
  {lessonId:49,difficulty:"Medium",title:"Transaction with Rollback",problemStatement:"Write a function that transfers money between accounts using a SQL transaction. Both the debit and credit must succeed or both must fail.",examples:"transfer(fromId, toId, amount) -> either both accounts updated or neither.",starterCodeJs:"async function transfer(db, fromAccountId, toAccountId, amount) {\n  if (amount <= 0) throw new Error('Amount must be positive');\n  const trx = await db.transaction();\n  try {\n    const from = await trx('accounts').where('id', fromAccountId).first();\n    if (!from) throw new Error('Source account not found');\n    if (from.balance < amount) throw new Error('Insufficient funds');\n    await trx('accounts').where('id', fromAccountId).decrement('balance', amount);\n    await trx('accounts').where('id', toAccountId).increment('balance', amount);\n    await trx('transactions').insert({\n      from_account_id: fromAccountId,\n      to_account_id: toAccountId,\n      amount,\n      created_at: new Date()\n    });\n    await trx.commit();\n    return { success: true, amount };\n  } catch (err) {\n    await trx.rollback();\n    throw err;\n  }\n}",hints:"Read-then-write requires a transaction to prevent race conditions. Check balance INSIDE transaction. Rollback in catch block.",solutionExplanation:"ACID transaction: debit+credit+log are atomic. Rollback restores original state. Without transaction, a crash between debit and credit loses money."},
  {lessonId:49,difficulty:"Medium",title:"Database Search with Full-Text",problemStatement:"Build a full-text search function for posts using SQL LIKE (with index awareness) and a relevance scoring approach.",examples:"search('node async') returns posts matching both words, scored by match count.",starterCodeJs:"async function searchPosts(db, query, limit = 20) {\n  const terms = query.trim().split(/\\s+/).filter(t => t.length >= 2);\n  if (!terms.length) return [];\n  // Simple multi-term search with relevance scoring\n  const conditions = terms.map(t => `(title LIKE ? OR body LIKE ?)`).join(' OR ');\n  const params = terms.flatMap(t => [`%${t}%`, `%${t}%`]);\n  // Score: count how many terms match\n  const scoreExpr = terms.map(t => `(CASE WHEN title LIKE ? THEN 2 ELSE 0 END + CASE WHEN body LIKE ? THEN 1 ELSE 0 END)`).join(' + ');\n  const scoreParams = terms.flatMap(t => [`%${t}%`, `%${t}%`]);\n  const rows = await db.all(\n    `SELECT id, title, substr(body, 1, 200) as excerpt, author_id, (${scoreExpr}) as score\n     FROM posts WHERE published = 1 AND (${conditions})\n     ORDER BY score DESC LIMIT ?`,\n    [...scoreParams, ...params, limit]\n  );\n  return rows;\n}",hints:"LIKE is case-insensitive in SQLite. Score title matches higher than body. For production use MySQL FULLTEXT or PostgreSQL tsvector.",solutionExplanation:"Basic search with LIKE. Relevance: title match=2, body match=1. Real FTS: MySQL FULLTEXT indexes, PostgreSQL tsvector, or Elasticsearch for production."},
  {lessonId:49,difficulty:"Hard",title:"Database Indexing Strategy",problemStatement:"Analyze and optimize a slow query by adding appropriate indexes. Show EXPLAIN before and after. Demonstrate composite index for common query pattern.",examples:"Query: WHERE status='active' AND created_at > ? ORDER BY created_at. Composite index on (status, created_at).",starterCodeJs:"// Schema setup with strategic indexes\nconst createIndexes = [\n  // Composite index for common filter+sort pattern\n  `CREATE INDEX IF NOT EXISTS idx_posts_status_created ON posts (status, created_at DESC)`,\n  // Partial index for active posts only (smaller, faster)\n  `CREATE INDEX IF NOT EXISTS idx_posts_active ON posts (created_at DESC) WHERE status = 'active'`,\n  // Covering index for user lookup + email (avoids table lookup)\n  `CREATE INDEX IF NOT EXISTS idx_users_email ON users (email)`,\n  // Index for foreign key join performance\n  `CREATE INDEX IF NOT EXISTS idx_posts_author ON posts (author_id)`,\n  // Composite for pagination query\n  `CREATE INDEX IF NOT EXISTS idx_comments_post_created ON comments (post_id, created_at ASC)`\n];\n// Analyzing with EXPLAIN:\nasync function analyzeQuery(db, sql, params) {\n  const plan = await db.all(`EXPLAIN QUERY PLAN ${sql}`, params);\n  const usesIndex = plan.some(row => row.detail.includes('USING INDEX') || row.detail.includes('SEARCH'));\n  console.log('Uses index:', usesIndex, plan.map(r => r.detail));\n  return { plan, usesIndex };\n}",hints:"Composite index column order matters: put equality conditions first, then range/sort. Covering index has all needed columns. EXPLAIN QUERY PLAN shows index usage.",solutionExplanation:"Index strategy: equality first (status), then range (created_at). Composite index covers WHERE+ORDER BY. EXPLAIN verifies index is used. Over-indexing slows writes."},
  {lessonId:49,difficulty:"Easy",title:"Parameterized Queries",problemStatement:"Demonstrate safe vs unsafe SQL queries. Show 5 examples of SQL injection attacks and how parameterized queries prevent them.",examples:"UNSAFE: 'SELECT * FROM users WHERE id=' + userId. SAFE: 'SELECT * FROM users WHERE id=?' with [userId]",starterCodeJs:"// UNSAFE - SQL injection vulnerable\nfunction unsafeGetUser(db, userId) {\n  return db.get(`SELECT * FROM users WHERE id = ${userId}`);\n  // Attack: userId = '1 OR 1=1' -> returns all users\n  // Attack: userId = '1; DROP TABLE users;' -> drops table\n}\n// SAFE - parameterized\nfunction safeGetUser(db, userId) {\n  return db.get('SELECT * FROM users WHERE id = ?', userId);\n}\n// UNSAFE - search\nfunction unsafeSearch(db, term) {\n  return db.all(`SELECT * FROM users WHERE name LIKE '%${term}%'`);\n  // Attack: term = \"' OR '1'='1\" -> returns all\n}\n// SAFE - parameterized LIKE\nfunction safeSearch(db, term) {\n  const escaped = term.replace(/[%_]/g, '\\\\$&');\n  return db.all('SELECT * FROM users WHERE name LIKE ?', `%${escaped}%`);\n}\n// UNSAFE - dynamic column\nfunction unsafeSort(db, column) {\n  return db.all(`SELECT * FROM users ORDER BY ${column}`);\n  // Attack: column = 'password' -> exposes passwords\n}\n// SAFE - whitelist columns\nconst ALLOWED_SORT = ['name','email','created_at'];\nfunction safeSort(db, column) {\n  const col = ALLOWED_SORT.includes(column) ? column : 'created_at';\n  return db.all(`SELECT * FROM users ORDER BY ${col}`);\n}",hints:"Parameterize everything from user input. Column/table names cannot be parameterized - use whitelist. Escape LIKE wildcards in the application.",solutionExplanation:"Parameterized queries prevent SQL injection by treating user input as data, not code. Column names need whitelist validation since they can't be parameterized."},
  {lessonId:49,difficulty:"Hard",title:"Database Pagination with Window Functions",problemStatement:"Use SQL window functions to implement efficient pagination with total count in one query, and add rank/row_number to results.",examples:"SELECT *, COUNT(*) OVER() as total, ROW_NUMBER() OVER(ORDER BY created_at) as row_num FROM posts",starterCodeJs:"async function getPaginatedPosts(db, options = {}) {\n  const { page = 1, limit = 20, status = 'published', orderBy = 'created_at', order = 'DESC' } = options;\n  const offset = (page - 1) * limit;\n  const rows = await db.all(`\n    SELECT\n      posts.*,\n      users.name as author_name,\n      COUNT(*) OVER() as total_count,\n      ROW_NUMBER() OVER(ORDER BY posts.${orderBy} ${order}) as row_num,\n      COUNT(comments.id) OVER(PARTITION BY posts.id) as comment_count\n    FROM posts\n    INNER JOIN users ON posts.author_id = users.id\n    LEFT JOIN comments ON comments.post_id = posts.id\n    WHERE posts.status = ?\n    GROUP BY posts.id\n    ORDER BY posts.${orderBy} ${order}\n    LIMIT ? OFFSET ?\n  `, [status, limit, offset]);\n  const total = rows[0]?.total_count || 0;\n  return { data: rows.map(r => { const {total_count,...rest} = r; return rest; }), pagination: { page, limit, total, pages: Math.ceil(total/limit) } };\n}",hints:"COUNT(*) OVER() without PARTITION gives total across all rows. ROW_NUMBER() OVER(ORDER BY) gives sequential numbers. Window functions avoid a second COUNT query.",solutionExplanation:"Window functions: COUNT(*) OVER() returns total in every row. Extract once and remove from result. Single query for data+total vs two separate queries."},
  {lessonId:49,difficulty:"Medium",title:"Audit Log Table",problemStatement:"Build a database audit log system that triggers log entries whenever users, posts, or comments are created/updated/deleted.",examples:"User updated -> insert into audit_logs: {table:'users', record_id:1, action:'UPDATE', changed_by:requestUser}",starterCodeJs:"// Create audit_logs table\nconst createAuditTable = `\n  CREATE TABLE IF NOT EXISTS audit_logs (\n    id INTEGER PRIMARY KEY AUTOINCREMENT,\n    table_name TEXT NOT NULL,\n    record_id INTEGER NOT NULL,\n    action TEXT NOT NULL CHECK(action IN ('CREATE','UPDATE','DELETE')),\n    old_data TEXT,\n    new_data TEXT,\n    changed_by INTEGER REFERENCES users(id),\n    ip_address TEXT,\n    created_at DATETIME DEFAULT CURRENT_TIMESTAMP\n  )\n`;\nasync function auditLog(db, { table, recordId, action, oldData, newData, changedBy, ipAddress }) {\n  await db.run(\n    `INSERT INTO audit_logs (table_name, record_id, action, old_data, new_data, changed_by, ip_address) VALUES (?,?,?,?,?,?,?)`,\n    [table, recordId, action, oldData ? JSON.stringify(oldData) : null, newData ? JSON.stringify(newData) : null, changedBy, ipAddress]\n  );\n}\nasync function updateUserWithAudit(db, id, data, requestUser) {\n  const old = await db.get('SELECT * FROM users WHERE id=?', id);\n  await db.run('UPDATE users SET name=?, email=? WHERE id=?', data.name, data.email, id);\n  const updated = await db.get('SELECT * FROM users WHERE id=?', id);\n  await auditLog(db, { table:'users', recordId:id, action:'UPDATE', oldData:old, newData:updated, changedBy:requestUser.id });\n}",hints:"Store JSON-stringified old and new data. Use a transaction to ensure the update and audit log succeed together.",solutionExplanation:"Audit log: record old and new state for UPDATE, only new for CREATE, only old for DELETE. Store in same transaction as the operation."},

  // Lesson 50 - NoSQL coding
  {lessonId:50,difficulty:"Easy",title:"In-Memory Key-Value Store",problemStatement:"Build a Redis-like key-value store with string, hash, list, and set data types. Support basic commands for each type.",examples:"kv.set('name','Alice'). kv.hset('user:1','name','Alice'). kv.lpush('queue', 'item').",starterCodeJs:"class KeyValueStore {\n  constructor() { this._store = new Map(); this._timers = new Map(); }\n  // String ops\n  set(key, value, ttl) { this._store.set(key, { type:'string', value: String(value) }); if (ttl) this._setTTL(key, ttl); return 'OK'; }\n  get(key) { const e = this._getEntry(key, 'string'); return e ? e.value : null; }\n  // Hash ops\n  hset(key, field, value) { const h = this._getOrCreate(key, 'hash', {}); h[field] = value; return 1; }\n  hget(key, field) { const e = this._getEntry(key, 'hash'); return e ? e[field] || null : null; }\n  hgetall(key) { const e = this._getEntry(key, 'hash'); return e ? {...e} : null; }\n  // List ops\n  lpush(key, ...values) { const l = this._getOrCreate(key, 'list', []); values.forEach(v => l.unshift(v)); return l.length; }\n  rpush(key, ...values) { const l = this._getOrCreate(key, 'list', []); values.forEach(v => l.push(v)); return l.length; }\n  lpop(key) { const e = this._getEntry(key, 'list'); return e ? e.shift() || null : null; }\n  lrange(key, start, stop) { const e = this._getEntry(key, 'list'); return e ? e.slice(start, stop < 0 ? undefined : stop+1) : []; }\n  // Set ops\n  sadd(key, ...members) { const s = this._getOrCreate(key, 'set', new Set()); members.forEach(m => s.add(m)); return members.length; }\n  sismember(key, member) { const e = this._getEntry(key, 'set'); return e ? e.has(member) : false; }\n  smembers(key) { const e = this._getEntry(key, 'set'); return e ? [...e] : []; }\n  _getEntry(key, type) { const e = this._store.get(key); return e?.type === type ? e.value : null; }\n  _getOrCreate(key, type, init) { if (!this._store.has(key)) this._store.set(key, { type, value: init }); return this._getEntry(key, type); }\n  _setTTL(key, ttl) { clearTimeout(this._timers.get(key)); this._timers.set(key, setTimeout(() => { this._store.delete(key); this._timers.delete(key); }, ttl * 1000)); }\n  del(key) { this._store.delete(key); clearTimeout(this._timers.get(key)); this._timers.delete(key); return 1; }\n  exists(key) { return this._store.has(key) ? 1 : 0; }\n}",hints:"Store type metadata with each entry to prevent cross-type operations. TTL via setTimeout per key. lrange stop=-1 means end of list.",solutionExplanation:"Redis-like store: typed entries prevent hash ops on strings. Each type has its own operations. TTL deletes key after timeout."},
  {lessonId:50,difficulty:"Medium",title:"Document Store with Indexing",problemStatement:"Build a simple document store that supports insert, find by query, and indexed lookups. Automatically index specified fields.",examples:"store.insert({name:'Alice',age:25,city:'NYC'}). store.find({city:'NYC'}) uses city index.",starterCodeJs:"class DocumentStore {\n  constructor({ indexes = [] } = {}) {\n    this._docs = new Map();\n    this._indexes = new Map();\n    this._idCounter = 1;\n    indexes.forEach(field => this._indexes.set(field, new Map()));\n  }\n  insert(doc) {\n    const _id = String(this._idCounter++);\n    const stored = { ...doc, _id };\n    this._docs.set(_id, stored);\n    for (const [field, index] of this._indexes) {\n      if (doc[field] !== undefined) {\n        const key = String(doc[field]);\n        if (!index.has(key)) index.set(key, new Set());\n        index.get(key).add(_id);\n      }\n    }\n    return stored;\n  }\n  find(query = {}) {\n    const queryEntries = Object.entries(query);\n    if (!queryEntries.length) return [...this._docs.values()];\n    // Use index for first indexed field found\n    for (const [field, value] of queryEntries) {\n      if (this._indexes.has(field)) {\n        const ids = this._indexes.get(field).get(String(value)) || new Set();\n        return [...ids].map(id => this._docs.get(id)).filter(doc => matchesQuery(doc, query));\n      }\n    }\n    return [...this._docs.values()].filter(doc => matchesQuery(doc, query));\n  }\n}\nfunction matchesQuery(doc, query) {\n  return Object.entries(query).every(([k,v]) => doc[k] === v);\n}",hints:"Indexes: Map<fieldValue, Set<docIds>>. Use index for first indexed field, then filter remaining conditions. Full scan fallback when no index.",solutionExplanation:"Index lookup: O(1) to find IDs by field value, then filter. Without index: O(n) full scan. Multi-field query uses one index + filter."},
  {lessonId:50,difficulty:"Medium",title:"Message Queue with Pub/Sub",problemStatement:"Build a publish/subscribe message queue. Publishers push to topics. Subscribers receive messages. Support durable (store if no subscriber) and ephemeral modes.",examples:"queue.subscribe('orders', handler). queue.publish('orders', {id:1}). Handler called with message.",starterCodeJs:"class PubSubQueue {\n  constructor() {\n    this._subscribers = new Map();\n    this._durable = new Map(); // stored messages when no subscriber\n  }\n  subscribe(topic, handler, { durable = false } = {}) {\n    if (!this._subscribers.has(topic)) this._subscribers.set(topic, new Set());\n    this._subscribers.get(topic).add(handler);\n    // Deliver stored messages\n    if (durable && this._durable.has(topic)) {\n      const messages = this._durable.get(topic);\n      messages.forEach(msg => handler(msg));\n      this._durable.delete(topic);\n    }\n    return () => this._subscribers.get(topic)?.delete(handler);\n  }\n  publish(topic, message) {\n    const subs = this._subscribers.get(topic);\n    if (!subs?.size) {\n      if (!this._durable.has(topic)) this._durable.set(topic, []);\n      this._durable.get(topic).push(message);\n      return 0;\n    }\n    subs.forEach(handler => { try { handler(message); } catch (err) { console.error(`Subscriber error on ${topic}:`, err); } });\n    return subs.size;\n  }\n  unsubscribeAll(topic) { this._subscribers.delete(topic); }\n}",hints:"subscribe() returns unsubscribe function. Durable: store messages when no subscriber, deliver on next subscribe. Catch handler errors to not crash publisher.",solutionExplanation:"Pub/Sub: publishers don't know subscribers. Durable mode stores messages for late subscribers. Return unsubscribe function (cleanup pattern)."},
  {lessonId:50,difficulty:"Easy",title:"LRU Cache Implementation",problemStatement:"Build an LRU (Least Recently Used) Cache class with O(1) get and set operations. Use a Map (preserves insertion order) as the backing store.",examples:"cache.set('a',1). cache.set('b',2). cache.get('a') moves 'a' to end. cache.set('c',3) evicts 'b' (oldest).",starterCodeJs:"class LRUCache {\n  constructor(capacity) {\n    this.capacity = capacity;\n    this._cache = new Map();\n  }\n  get(key) {\n    if (!this._cache.has(key)) return -1;\n    const value = this._cache.get(key);\n    this._cache.delete(key);\n    this._cache.set(key, value); // move to end (most recently used)\n    return value;\n  }\n  set(key, value) {\n    if (this._cache.has(key)) this._cache.delete(key); // update: move to end\n    else if (this._cache.size >= this.capacity) {\n      const oldestKey = this._cache.keys().next().value; // first key = least recently used\n      this._cache.delete(oldestKey);\n    }\n    this._cache.set(key, value);\n  }\n  peek(key) { return this._cache.has(key) ? this._cache.get(key) : -1; } // no LRU update\n  has(key) { return this._cache.has(key); }\n  size() { return this._cache.size; }\n  keys() { return [...this._cache.keys()]; }\n}",hints:"Map preserves insertion order. Delete+re-insert moves to end. First key is oldest (LRU). This gives O(1) get/set because Map operations are O(1).",solutionExplanation:"LRU via Map: Map.keys().next() gives oldest entry. Delete+re-insert on access moves to 'end'. Evict first entry when over capacity."}
];

async function main() {
  let ci = 0, cs = 0;
  for (const q of codingQuestions) {
    const exists = await p.practiceQuestion.findFirst({ where: { lessonId: q.lessonId, title: q.title } });
    if (!exists) { await p.practiceQuestion.create({ data: q }); ci++; } else cs++;
  }
  console.log(`Coding: ${ci} inserted, ${cs} skipped.`);
}

main().catch(console.error).finally(() => p.$disconnect());
